        Set-Content -LiteralPath $p -Value '{ "name":"a","version":"1.0.0","scripts":{}}'
        Set-VersionInFile -Path $p -Version '2.0.0'
        $raw = Get-Content -LiteralPath $p -Raw
        $raw   | Should -Match '"version":"2.0.0"'
        $raw   | Should -Match '"name":"a"'
