        @'
feat: one
---
fix: two
---
feat!: three
'@ | Set-Content -LiteralPath $p
        $c = Read-CommitFixture -Path $p
        $c.Count | Should -Be 3
        $c[0]    | Should -Be 'feat: one'
        $c[2]    | Should -Be 'feat!: three'
    }
}

Describe 'Invoke-VersionBump (end-to-end)' {
    It 'bumps minor and writes changelog' {
